from langflow.custom import Component
from langflow.io import DropdownInput, MessageInput, Output, StrInput
from langflow.schema.message import Message


class AppendMessageToFile(Component):
    display_name = "Append Message to File"
    description = "Append message text to an existing file."
    icon = "save"
    name = "AppendMessageToFile"

    inputs = [
        MessageInput(
            name="message",
            display_name="Message",
            info="Message to append",
            dynamic=True,
            show=True,
        ),
        DropdownInput(
            name="file_format",
            display_name="File Format",
            options=["txt", "jsonl", "markdown"],
            value="txt",
        ),
        StrInput(
            name="file_path",
            display_name="File Path (including filename)",
            value="./log",
        ),
    ]

    outputs = [
        Output(
            name="confirmation",
            display_name="Confirmation",
            method="append_to_file",
        ),
    ]

    # ---------- MAIN METHOD ----------
    def append_to_file(self) -> Message:
        path = Path(self.file_path).expanduser()
        if not path.parent.exists():
            path.parent.mkdir(parents=True, exist_ok=True)

        path = self._adjust_path(path, self.file_format)
        content = self._extract_content(self.message)

        if self.file_format == "txt":
            with path.open("a", encoding="utf-8") as f:
                f.write(content + "\n")
        elif self.file_format == "jsonl":
            with path.open("a", encoding="utf-8") as f:
                f.write(json.dumps({"message": content}, ensure_ascii=False) + "\n")
        elif self.file_format == "markdown":
            with path.open("a", encoding="utf-8") as f:
                f.write(f"\n\n**Message:**\n\n{content}\n")
        else:
            raise ValueError(f"Unsupported format: {self.file_format}")

        # ❗ FIX: instantiate Message with keyword arg
        return Message(text=f"Appended message to '{path}'")

    # ---------- HELPERS ----------
    def _extract_content(self, message: Message) -> str:
        if message.text is None:
            return ""
        if isinstance(message.text, str):
            return message.text
        if hasattr(message.text, "__iter__"):
            return " ".join(str(item) for item in message.text)
        return str(message.text)

    def _adjust_path(self, path: Path, fmt: str) -> Path:
        ext    = path.suffix.lower().lstrip(".")
        target = "json" if fmt == "jsonl" else fmt
        return Path(f"{path}.{target}") if ext != target else path

